CODE_EXAMPLE:
public class UserRepository {
  public User GetById(int id) => new User { Id = id };

  // Renamed from Get to GetById for clarity
  public User GetByIdRenamed(int id) => new User { Id = id };
}

UNIT_TEST_EXAMPLE:
[TestMethod]
public void GetByIdRenamed_ReturnsExpectedUser() {
  var repo = new UserRepository();
  var user = repo.GetByIdRenamed(5);
  Assert.AreEqual(5, user.Id);
}

[TestMethod]
public void Rename_DoesNotChangeBehavior() {
  var repo = new UserRepository();
  Assert.AreEqual(repo.GetById(7).Id, repo.GetByIdRenamed(7).Id);
}
